class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator still works because we configured
        // HasDiscriminator<string>("Discriminator") in OnModelCreating.
        // EF9 now requires VALUE in projections; SELECT * is unaffected.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Sync I/O (ToList) now throws; must use async
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

